def can_jump(A : List[int], start_index:int =0):
    end_index = len(A) - 1
       
    def can_jump_(A, curr_index, end_index):
        # If the index value is 0, cannot jump further, we are blocked
        if A[curr_index] == 0:
            return False
        print(curr_index, end_index)
        #Reached the end of the array, so we found a path
        if curr_index == end_index:
            return True
        #max_next_index determines the maximum we can jump, it should not exceed the length of the array, so taking min of both
        max_next_index = min(end_index, curr_index + A[curr_index])
        print(max_next_index)
        while max_next_index > curr_index:
            # max_next_index becomes the curr_index now
            if can_jump_(A, max_next_index, end_index):
                return True
            max_next_index -= 1
        return False
    return can_jump_(A, 0, len(A)-1)


def _tower_of_hanoi(num_disks, from_, to_, spare_, result):
    if num_disks == 0:
        return
    # Move n-1 disks from 'from_' to 'spare_', using 'to_' as spare
    _tower_of_hanoi(num_disks-1, from_, spare_, to_, result)
    # Move 1 disk from 'from_' to 'to_'
    result.append((from_, to_, num_disks-1))
    # Move n-1 disks from 'spare_' to 'to_', using 'from_' as spare
    _tower_of_hanoi(num_disks-1, spare_, to_, from_, result)
    return



def test_tower_hanoi(n):
    from_, to_, spare_ = "f", "t", "s"
    result = []
    _tower_of_hanoi(n, from_, to_, spare_, result)
    with open("tower_hanoi.txt", "w") as f:
        pprint.pprint(result, stream=f, width=100)
    return

